"use client";

import { useGSAP } from "@gsap/react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { Mic, Bot, TrendingUp } from "lucide-react";
import { useRef } from "react";
import { GlassCard } from "@/components/ui/GlassCard";

const STEPS = [
    {
        icon: Mic,
        title: "1. Speak",
        description: "Open your mic and talk naturally. No typing allowed.",
        color: "text-primary",
        bg: "bg-primary/20",
    },
    {
        icon: Bot,
        title: "2. NOVA Listens",
        description: "AI corrects your grammar and pronunciation instantly.",
        color: "text-secondary",
        bg: "bg-secondary/20",
    },
    {
        icon: TrendingUp,
        title: "3. You Improve",
        description: "See your fluency scores grow daily on your dashboard.",
        color: "text-success",
        bg: "bg-success/20",
    },
];

export function HowItWorksSection() {
    const containerRef = useRef<HTMLDivElement>(null);

    useGSAP(() => {
        if (!containerRef.current) return;

        gsap.from(".step-card", {
            scrollTrigger: {
                trigger: containerRef.current,
                start: "top 80%",
            },
            y: 50,
            opacity: 0,
            duration: 0.8,
            stagger: 0.2,
            ease: "power2.out",
        });
    }, { scope: containerRef });

    return (
        <section id="how-it-works" className="py-24 relative" ref={containerRef}>
            <div className="container mx-auto px-4 md:px-8">
                <div className="text-center max-w-3xl mx-auto mb-16">
                    <h2 className="text-3xl md:text-5xl font-heading font-bold mb-6">How it Works</h2>
                    <p className="text-lg text-muted-foreground">Three simple steps to fluency. It feels like chatting with a friend who happens to be a perfect English teacher.</p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 relative">
                    {/* Desktop Connecting Line */}
                    <div className="hidden md:block absolute top-[4.5rem] left-[15%] right-[15%] h-px bg-gradient-to-r from-transparent via-white/20 to-transparent -z-10" />

                    {STEPS.map((step, i) => (
                        <GlassCard key={step.title} className="step-card flex flex-col items-center text-center relative group hover:border-white/20 transition-colors">
                            <div className={`h-20 w-20 rounded-2xl ${step.bg} ${step.color} flex items-center justify-center mb-6 transform group-hover:-translate-y-2 transition-transform duration-300`}>
                                <step.icon className="h-10 w-10" />
                            </div>
                            <h3 className="text-2xl font-bold font-heading mb-4 text-white">{step.title}</h3>
                            <p className="text-muted-foreground">{step.description}</p>
                        </GlassCard>
                    ))}
                </div>
            </div>
        </section>
    );
}

import { Marquee } from "@/components/ui/Marquee";
import { GlassCard } from "@/components/ui/GlassCard";
import { Star } from "lucide-react";
import Image from "next/image";

const TESTIMONIALS = [
    { name: "Rahul Sharma", country: "­ƒç«­ƒç│", role: "Software Engineer", quote: "Got my dream job at a US startup. NOVA built my confidence to speak freely without translating in my head." },
    { name: "Ana Silva", country: "­ƒçº­ƒçÀ", role: "UX Designer", quote: "The real-time grammar correction is mind-blowing. It's like having a native speaker correct you gently." },
    { name: "Yuki Tanaka", country: "­ƒç»­ƒçÁ", role: "Sales Manager", quote: "I no longer fear English meetings. The practice loops and daily challenges forced me to speak." },
    { name: "Carlos Mendoza", country: "­ƒç▓­ƒç¢", role: "Student", quote: "I tried typing-based apps for years and couldn't speak. VoiceUp changed that in 3 months." },
    { name: "Sarah M├╝ller", country: "­ƒç®­ƒç¬", role: "Marketing Lead", quote: "Perfect preparation for international conferences. Fast, effective, and actually fun to use." },
    { name: "David Chen", country: "­ƒç╣­ƒç╝", role: "Frontend Developer", quote: "VoiceUp's interview scenarios are exactly what you need. Zero anxiety now when taking calls." },
    { name: "Emily Kim", country: "­ƒç░­ƒçÀ", role: "Product Manager", quote: "The best English learning investment I've never had to pay for. Absolutely incredible." },
    { name: "Omar Hassan", country: "­ƒç¬­ƒç¼", role: "Cloud Architect", quote: "Fluent English was the missing piece in my career. NOVA helped me find it." },
];

export function TestimonialsSection() {
    const row1 = TESTIMONIALS.slice(0, 4);
    const row2 = TESTIMONIALS.slice(4, 8);

    return (
        <section className="py-24 relative overflow-hidden">
            <div className="container mx-auto px-4 md:px-8 mb-16 text-center">
                <h2 className="text-3xl md:text-5xl font-heading font-bold mb-4">Loved by learners worldwide</h2>
                <p className="text-lg text-muted-foreground">Join 500,000+ people who found their voice with VoiceUp.</p>
            </div>

            <div className="flex flex-col gap-8 relative overflow-hidden">
                <Marquee direction="left" speed="slow" pauseOnHover>
                    {row1.map((testimonial, i) => (
                        <TestimonialCard key={i} {...testimonial} idx={i} />
                    ))}
                </Marquee>

                <Marquee direction="right" speed="slow" pauseOnHover>
                    {row2.map((testimonial, i) => (
                        <TestimonialCard key={i} {...testimonial} idx={i + 4} />
                    ))}
                </Marquee>

                {/* Gradient Edges */}
                <div className="pointer-events-none absolute inset-y-0 left-0 w-1/4 bg-gradient-to-r from-background to-transparent z-10" />
                <div className="pointer-events-none absolute inset-y-0 right-0 w-1/4 bg-gradient-to-l from-background to-transparent z-10" />
            </div>
        </section>
    );
}

interface TestimonialCardProps {
    name: string;
    country: string;
    role: string;
    quote: string;
    idx: number;
}

function TestimonialCard({ name, country, role, quote, idx }: TestimonialCardProps) {
    return (
        <GlassCard className="w-[350px] md:w-[400px] flex-shrink-0 mx-2 flex flex-col justify-between h-full bg-surface/50 border-white/5 hover:border-white/20 transition-colors">
            <div className="flex flex-col gap-4">
                <div className="flex text-warning text-sm">
                    {[1, 2, 3, 4, 5].map((i) => (
                        <Star key={i} className="h-4 w-4 fill-current" />
                    ))}
                </div>
                <q className="text-base text-white/90 italic leading-relaxed">"{quote}"</q>
            </div>
            <div className="flex items-center gap-4 mt-6 pt-6 border-t border-white/5">
                <div className="h-12 w-12 rounded-full overflow-hidden bg-surface-raised border border-white/10 relative">
                    <Image src={`https://i.pravatar.cc/150?img=${idx + 20}`} fill sizes="48px" alt={name} className="object-cover" />
                </div>
                <div className="flex flex-col">
                    <span className="font-heading font-bold text-white flex items-center gap-2">
                        {name} <span className="text-lg">{country}</span>
                    </span>
                    <span className="text-xs text-muted-foreground">{role}</span>
                </div>
            </div>
        </GlassCard>
    );
}
